if let BarInfo::Memory { address_type, address, size, .. } = info { if size > 0 && address == 0 { // 需要分配的未初始化BAR let new_addr = allocator .as_mut() .expect("No memory ranges available for PCI BARs!") .alloc(size as _) .ok_or(DevError::NoMemory)?; if address_type == MemoryBarType::Width32 { root.set_bar_32(bdf, bar, new_addr as _); } else if address_type == MemoryBarType::Width64 { root.set_bar_64(bdf, bar, new_addr); } }
} 检查当前BAR是否占用两个条目，若当前BAR是64位类型，则需递增bar两次，跳过下一个索引。 bar += 1;
if info.takes_two_entries() { bar += 1;
} 启用设备的IO/内存访问及总线主控 let (_status, cmd) = root.get_status_command(bdf); root.set_command( bdf, cmd | Command::IO_SPACE | Command::MEMORY_SPACE | Command::BUS_MASTER, ); 命令寄存器设置 ： IO_SPACE : 允许设备响应IO端口访问。 MEMORY_SPACE : 允许设备响应内存映射访问。 BUS_MASTER : 启用设备作为总线主设备。

